UPDATE public.agent_skills SET tool_definition = jsonb_set(tool_definition, '{function,parameters,properties,value}', '{"type": "string", "description": "Information to remember"}'::jsonb) WHERE name = 'memory_write' AND tool_definition->'function'->'parameters'->'properties'->'value'->>'type' IS NULL; UPDATE public.agent_skills SET tool_definition = jsonb_set(tool_definition, '{function,parameters,properties,value}', '{"type": "string", "description": "New value"}'::jsonb) WHERE name = 'update_settings' AND tool_definition->'function'->'parameters'->'properties'->'value'->>'type' IS NULL;